import React, { useState, useEffect } from 'react';
import { QRCodeCanvas } from 'qrcode.react';
import { useNavigate } from 'react-router-dom';
import './Registration.css';
import { saveFormData } from '../db/indexedDB';

const Registration = () => {
    const [formData, setFormData] = useState({
        type: 'staff',
        additionalFields: {},
    });
    const [message, setMessage] = useState('');
    const [suppliers, setSuppliers] = useState([]);
    const [qrCodeData, setQrCodeData] = useState('');
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        const fetchSuppliers = async () => {
            try {
                const response = await fetch('http://localhost:8000/api/v1/suppliers');
                const data = await response.json();
                setSuppliers(data);
            } catch (error) {
                console.error('Error fetching suppliers:', error);
            }
        };

        fetchSuppliers();
    }, []);

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setFormData({ ...formData, [name]: value });
    };

    const handleAdditionalFieldsChange = (e) => {
        const { name, value } = e.target;
        setFormData({
            ...formData,
            additionalFields: { ...formData.additionalFields, [name]: value },
        });
    };

    const calculateAge = (dob) => {
        const birthDate = new Date(dob);
        const today = new Date();
        let age = today.getFullYear() - birthDate.getFullYear();
        const monthDiff = today.getMonth() - birthDate.getMonth();
        if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birthDate.getDate())) {
            age--;
        }
        return age;
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setMessage('');
        try {
            // Map formData to backend schema
            const payload = {
                username: formData.additionalFields?.username || formData.username || '',
                password: formData.additionalFields?.password || formData.password || '',
                role: formData.type || formData.role || '',
                // Optionally add facial_scan_data and qr_code if available
            };
            const response = await fetch('http://localhost:8000/api/v1/registration/register', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(payload),
            });
            let data;
            try {
                data = await response.json();
            } catch (jsonErr) {
                data = {};
            }
            if (response.ok) {
                setMessage(typeof data.message === 'string' ? data.message : 'Registration successful!');
                setQrCodeData(JSON.stringify(payload));
                await saveFormData(payload);
                setFormData({ type: 'staff', additionalFields: {} });
                setLoading(false);
            } else {
                let errorMsg = 'Registration failed. Please try again.';
                if (data.detail) {
                    if (typeof data.detail === 'string') {
                        errorMsg = data.detail;
                    } else if (Array.isArray(data.detail)) {
                        errorMsg = data.detail.map(d => d.msg || JSON.stringify(d)).join('; ');
                    } else if (typeof data.detail === 'object') {
                        errorMsg = JSON.stringify(data.detail);
                    }
                }
                setMessage(errorMsg);
                setLoading(false);
            }
        } catch (error) {
